import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed


const WeatherIcon = (condition?: string) => {
  switch (condition?.toLowerCase()) {
    case 'sunny': return '☀️';
    case 'cloudy': return '☁️';
    case 'rainy': return '🌧️';
    case 'snowy': return '❄️';
    default: return '🌤️';
  }
};

export default function Component(props: Props) {
  const [refreshing, setRefreshing] = useState(false);
  const handleRefresh = useCallback(() => {
    setRefreshing(true);
    setTimeout(() => setRefreshing(false), 800);
  }, []);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="lg" radius="xl">
        <Stack gap="var(--ggui-spacing-8)">
          <Row justify="between" align="center">
            <Heading level={3}>{props.city}</Heading>

            <Button as={Clickable} onClick={handleRefresh} variant="ghost">
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Icon name="refresh-cw" />
                {refreshing ? <Spinner size="sm" /> : <Text>Refresh</Text>}
              </Row>
            </Button>

          </Row>

          <Stack align="center" gap="var(--ggui-spacing-2)">
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
              {props.condition}
            </Text>
            <Text size="4xl" weight="bold">
              {props.temperature}°{props.unit}
            </Text>
            <Box padding="var(--ggui-spacing-4)">
              <Text size="4xl">{WeatherIcon(props.condition)}</Text>
            </Box>
          </Stack>

          <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-radius-md)">
            <Row justify="between">
              <Stack align="center">
                <Text variant="label">Humidity</Text>
                <Text weight="bold">{props.humidity}%</Text>
              </Stack>
              <Divider orientation="vertical" />
              <Stack align="center">
                <Text variant="label">Wind Speed</Text>
                <Text weight="bold">{props.windSpeed} km/h</Text>
              </Stack>
            </Row>
          </Box>

          {(props.forecast || []).length > 0 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>5-Day Forecast</Heading>
              <Row gap="var(--ggui-spacing-2)" justify="between">
                {(props.forecast || []).map((f, i) => (
                  <Stack key={i} align="center" gap="var(--ggui-spacing-1)">
