interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-400)',
  'alkaline-earth-metal': 'var(--ggui-color-success-400)',
  'transition-metal': 'var(--ggui-color-warning-400)',
  'post-transition-metal': 'var(--ggui-color-info-400)',
  'metalloid': 'var(--ggui-color-primary-200)',
  'reactive-nonmetal': 'var(--ggui-color-error-400)',
  'noble-gas': 'var(--ggui-color-success-600)',
  'lanthanide': 'var(--ggui-color-primary-300)',
  'actinide': 'var(--ggui-color-primary-200)',
  'unknown': 'var(--ggui-color-outlineVariant)',
};

const formatCategory = (cat: string) => 
  cat.split('-').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');

const ElementCell = ({ element, onClick }: { element: any; onClick: () => void }) => {
  const bgColor = getCategoryColor(element.category);

  return (
    <Box
      as={Clickable}
      onClick={onClick}
      role="button"
      aria-label={`Element ${element.name} (${element.symbol})`}
      borderRadius="var(--ggui-shape-radius-md)"
      background={bgColor}
      padding="var(--ggui-spacing-2)"
      style={{
        gridRow: element.row,
        gridColumn: element.col,
        aspectRatio: '1',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        cursor: 'pointer',
        border: '1px solid var(--ggui-color-outlineVariant)',
        transition: 'transform 0.2s, filter 0.2s',
      }}
      className="hover:scale-105 hover:brightness-110 focus:ring-2 focus:ring-offset-2"
    >
      <Text variant="caption" style={{ alignSelf: 'flex-start', fontSize: '10px' }}>{element.atomicNumber}</Text>
      <Heading level={5}>{element.symbol}</Heading>
    </Box>
  );
};


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<any>(null);

  const filteredElements = useMemo(() => {
    return (props.elements || []).filter(
      (el) =>
        el.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        el.symbol?.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [props.elements, searchTerm]);

  const categories = useMemo(() => {
    const cats = Array.from(new Set((props.elements || []).map((e) => e.category)));
    return cats.filter(Boolean);
  }, [props.elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table</Heading>

        <Input 
          label="Search Elements" 
          placeholder="Search by name or symbol..." 
          value={searchTerm} 
          onChange={(e: any) => setSearchTerm(e.target.value)} 
        />


        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: '4px' }}>
          {filteredElements.map((el) => (
            <ElementCell key={el.atomicNumber} element={el} onClick={() => setSelectedElement(el)} />
          ))}
        </Box>

        <Row wrap gap="var(--ggui-spacing-3)" justify="center">
          {categories.map((cat) => (
            <Tag key={cat} variant="default">
              <Box borderRadius="50%" background={getCategoryColor(cat)} style={{ width: 10, height: 10, marginRight: 8 }} />
              <Text variant="caption">{formatCategory(cat || 'unknown')}</Text>
            </Tag>
          ))}
        </Row>



        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
              <Button onClick={() => setSelectedElement(null)} variant="outline">Close</Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

