            </Card>
          ))}
        </Stack>
      ),
    },
  ], [product.description, product.specifications, product.reviews]);

  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Stack direction="horizontal" gap="var(--ggui-spacing-6)" wrap>
          <Box borderRadius="var(--ggui-shape-radius-lg)" background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-10)" style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={2} align="center">{product.name}</Heading>
          </Box>
          <Stack gap="var(--ggui-spacing-3)" style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">{product.currency} {product.price}</Text>
            <RatingStars rating={product.rating || 0} />
            <Badge variant={(product.stock || 0) > 5 ? 'success' : 'warning'}>
              {(product.stock || 0) > 0 ? ((product.stock || 0) > 5 ? 'In Stock' : 'Low Stock') : 'Out of Stock'}
            </Badge>
          </Stack>
        </Stack>

        <Tabs items={tabs} activeKey={activeTab} onChange={setActiveTab} />

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Button size="sm" onClick={() => setQuantity((q) => Math.max(1, q - 1))}>-</Button>
              <Input
                label="Quantity"
                type="number"
                value={quantity.toString()}
                onChange={(value) => setQuantity(Math.max(1, Math.min(product.stock || 1, parseInt(value) || 1)))}
                style={{ width: '80px' }}
              />
              <Button size="sm" onClick={() => setQuantity((q) => Math.min(product.stock || 1, q + 1))}>+</Button>
            </Row>
            <Button
              variant="primary"
              disabled={isOutOfStock}
              onClick={handleAddToCart}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

