interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




const ChatMessage = ({ sender, text, timestamp, isOwn }: { sender?: string; text?: string; timestamp?: string; isOwn: boolean }) => (
  <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
      {sender} • {timestamp ? new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
    </Text>
    <Box 
      padding="var(--ggui-spacing-3)" 
      borderRadius="var(--ggui-shape-radius-lg)"
      background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
    >
      <Text color={isOwn ? 'var(--ggui-color-onPrimary)' : 'var(--ggui-color-onSurface)'}>{text}</Text>
    </Box>
  </Stack>
);


export default function Component(props: Props) {
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  const [inputText, setInputText] = useState('');
  const [messages, setMessages] = useState(props.messages || []);
  const [typingSenders, setTypingSenders] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (message.latest) setMessages((prev) => [...prev, message.latest!]);
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest) {
      setTypingSenders((prev) => {
        const next = new Set(prev);
        if (typing.latest?.active) next.add(typing.latest.sender || 'Someone');
        else next.delete(typing.latest.sender || 'Someone');
        return next;
      });
    }
  }, [typing.latest]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, typingSenders]);

  const handleSend = useCallback(() => {
    if (!inputText.trim()) return;
    const msg = { sender: props.currentUser, text: inputText, timestamp: new Date().toISOString() };
    setMessages((prev) => [...prev, msg]);
    sendMessage({ text: inputText, timestamp: msg.timestamp });
    setInputText('');
  }, [inputText, props.currentUser, sendMessage]);
  const groupedMessages = useMemo(() => {
    const groups: { sender?: string; messages: typeof messages }[] = [];
    messages.forEach((m) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === m.sender) {
        last.messages.push(m);
      } else {
        groups.push({ sender: m.sender, messages: [m] });
      }
    });
    return groups;
  }, [messages]);


  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Card padding="var(--ggui-spacing-4)" shadow="md" style={{ display: 'flex', flexDirection: 'column', height: '80vh' }}>
        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-3)">
          <Box paddingBottom="var(--ggui-spacing-3)">
            <Heading level={3}>{props.title}</Heading>
          </Box>
          <Badge variant="default">{props.participantCount} Participants</Badge>
          {typingSenders.size > 0 && (
            <Text variant="caption" color="var(--ggui-color-primary-600)">
              {Array.from(typingSenders).join(', ')} {typingSenders.size === 1 ? 'is' : 'are'} typing...
            </Text>
          )}
        </Stack>
        <Divider />
        <Box paddingY="var(--ggui-spacing-4)" style={{ flex: 1, overflowY: 'auto' }} role="log" aria-label="Chat messages" aria-live="polite">
          <Stack gap="var(--ggui-spacing-4)">
            {groupedMessages.map((group, groupIdx) => (
              <Stack key={groupIdx} gap="var(--ggui-spacing-2)">
                {group.messages.map((m, i) => (
                  <ChatMessage 
                    key={i} 
                    sender={i === 0 ? m.sender : undefined} 
                    text={m.text} 
                    timestamp={m.timestamp} 
                    isOwn={m.sender === props.currentUser} 
                  />
                ))}
              </Stack>
            ))}
            <div ref={messagesEndRef} />
          </Stack>
        </Box>

        <Divider />
        <Box paddingY="var(--ggui-spacing-3)">
          <Row gap="var(--ggui-spacing-2)">
            <Box style={{ flex: 1 }}>
              <Input 
                label="Compose message" 
                value={inputText} 
                onChange={setInputText} 
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              />
            </Box>
            <Button as={Clickable} onClick={handleSend} disabled={!inputText.trim()}>Send</Button>
          </Row>
        </Box>
      </Card>
    </Container>

  );

}

