const StockCard = ({ stock }: { stock: any }) => {
  const isPositive = (stock.change || 0) >= 0;
  const color = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  const prevPriceRef = useRef<number | undefined>(stock.price);
  const [shouldAnimate, setShouldAnimate] = useState(false);

  useEffect(() => {
    if (prevPriceRef.current !== undefined && prevPriceRef.current !== stock.price) {
      setShouldAnimate(true);
      const timer = setTimeout(() => setShouldAnimate(false), 1000);
      return () => clearTimeout(timer);
    }
    prevPriceRef.current = stock.price;
  }, [stock.price]);

  return (
    <Card 
      padding="var(--ggui-spacing-4)" 
      style={{ 
        border: `1px solid ${color}`,
        animation: shouldAnimate ? animation.flash : 'none',
        '--ggui-flash-color': isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)'
      } as React.CSSProperties}
    >
      <Stack gap="var(--ggui-spacing-2)">
        <Row justify="between" align="center">
          <Heading level={3}>{stock.symbol}</Heading>
          <Text variant="caption">{stock.name}</Text>
        </Row>
        <Heading level={2}>${stock.price?.toFixed(2)}</Heading>
        <Row gap="var(--ggui-spacing-2)" align="center">
          <Text style={{ color }} weight="bold">
            {isPositive ? '+' : ''}{stock.change?.toFixed(2)}
          </Text>
          <Badge variant={isPositive ? 'success' : 'error'}>
            <Row align="center" gap="var(--ggui-spacing-1)">
              <Text variant="caption" color="currentColor">{isPositive ? '▲' : '▼'}</Text>
              <Text variant="caption" color="currentColor">{stock.changePercent?.toFixed(2)}%</Text>
            </Row>
